import com.sap.gateway.ip.core.customdev.util.Message
import groovy.json.JsonSlurper
import groovy.json.JsonOutput

def Message processData(Message message) {
    def body = message.getBody(String)
    def jsonSlurper = new JsonSlurper()
    def payload = jsonSlurper.parseText(body)

    def seedYear = ""
    def contactInfo = payload.ProductBooking.Header.From.PartnerInformation.ContactInformation.find { it.ContactDescription == "SeedYear" }
    if (contactInfo?.ContactName) {
        seedYear = contactInfo.ContactName
    }
    def shipToList = []
    def ProductBookingBodies = payload.ProductBooking.ProductBookingBody
    if (!(ProductBookingBodies instanceof List)) {
       ProductBookingBodies = [ProductBookingBodies]
    }
    ProductBookingBodies.each { productBookingBody ->
        def shipToInfo = productBookingBody?.ProductBookingPartners?.ShipTo ?: [:]
        shipToList << shipToInfo
    }
    def outputJson = JsonOutput.toJson(shipToList)


    // Extract ProductIdentifiers
    def productIdentifiers = []
    ProductBookingBodies.each { productBookingBody ->
        def productBookingDetails = productBookingBody.ProductBookingDetails
        if (productBookingDetails instanceof List) {
            productBookingDetails.each { productBookingDetail ->
                def productLineItems = productBookingDetail .ProductBookingProductLineItem
                if (productLineItems instanceof List) {
                    productLineItems.each { productLineItem ->
                        def productIdentifier = productLineItem?.ProductIdentification?.ProductIdentifier
                        if (productIdentifier) {
                            productIdentifiers << productIdentifier
                        }
                    }
                } else if (productLineItems instanceof Map) {
                    def productIdentifier = productLineItems?.ProductIdentification?.ProductIdentifier
                    if (productIdentifier) {
                        productIdentifiers << productIdentifier
                    }
                }
            }
        } else if (productBookingDetails instanceof Map) {
            def productLineItems = productBookingDetails.ProductBookingProductLineItem
            if (productLineItems instanceof List) {
                productLineItems.each { productLineItem ->
                    def productIdentifier = productLineItem?.ProductIdentification?.ProductIdentifier
                    if (productIdentifier) {
                        productIdentifiers << productIdentifier
                    }
                }
            } else if (productLineItems instanceof Map) {
                def productIdentifier = productLineItems?.ProductIdentification?.ProductIdentifier
                if (productIdentifier) {
                    productIdentifiers << productIdentifier
                }
            }
        }
    }
    // Remove duplicates
    productIdentifiers = productIdentifiers.unique()

    // Map each element to add single quotes
    def quotedProductIdentifiers = productIdentifiers.collect { "'${it}'" }

    // Join the array back into a comma-separated string
    def GTINSeperatedCommas = quotedProductIdentifiers.join(',')
    def productIdentifiersJson = JsonOutput.toJson(productIdentifiers)
    def partnerIdentifier = payload.ProductBooking.Header.From.PartnerInformation.PartnerIdentifier ?: null
    if (partnerIdentifier instanceof List) {
        partnerIdentifier = partnerIdentifier.collect { "'${it}'" }
    } else if (partnerIdentifier) {
        partnerIdentifier = "'${partnerIdentifier}'"
    }

    def buyerPartnerIdentifiers = []
    ProductBookingBodies.each { ProductBookingBody ->
        def buyerInfo = ProductBookingBody?.ProductBookingPartners?.Buyer?.PartnerInformation?.PartnerIdentifier
        if (buyerInfo && buyerInfo instanceof List) {
            buyerPartnerIdentifiers << "'${buyerInfo[0]}'" // Access the first PartnerIdentifier and enclose in single quotes
        } else if (buyerInfo) {
            buyerPartnerIdentifiers << "'${buyerInfo}'" // Handle case where PartnerIdentifier is not a list and enclose in single quotes
        }
    }
// krishna changes for resellerGLN
def resellerGLN = buyerPartnerIdentifiers ? buyerPartnerIdentifiers[0] : ''
    // def resellerGLN = buyerPartnerIdentifiers.join(',')
    // Extract ShipTo.PartnerInformation.PartnerIdentifier
    def shipToPartnerIdentifiers = []
    ProductBookingBodies.each { productBookingBody ->
        def shipToInfo = productBookingBody?.ProductBookingPartners?.ShipTo?.PartnerInformation?.PartnerIdentifier
        if (shipToInfo) {
            shipToPartnerIdentifiers << shipToInfo
        }
    }
    // Remove duplicates
    shipToPartnerIdentifiers = shipToPartnerIdentifiers.unique()

    def growerGLNSeperatedCommas = shipToPartnerIdentifiers.join(',')

    def growerGLN = JsonOutput.toJson(shipToPartnerIdentifiers)

    // Set properties
    message.setProperty("seedYear", seedYear)
    message.setProperty("resellerGLN", resellerGLN)
    message.setProperty("partnerIdentifier", partnerIdentifier)
    message.setProperty("growerAddress", outputJson)
    message.setProperty("GTINSeperatedCommas", GTINSeperatedCommas)
    message.setProperty("growerGLN", growerGLN)
    message.setProperty("growerGLNSeperatedCommas", growerGLNSeperatedCommas)
    message.setProperty("GTIN", productIdentifiersJson)

    return message
}

import com.sap.gateway.ip.core.customdev.util.Message
import groovy.json.JsonOutput
import groovy.json.JsonSlurper

def processData(Message message) {
    // JSON body to be stored as a property
    def jsonBody = '''
    {
        "EC002": "Blank Purchase Order Number-Purchase Order Number Must Be Present For Order Management",
        "EC005": "Request Type Is Not Allowed-Request Type Must Be New, Changed, Cancelled Or SummaryRequest",
        "EC006": "Order Type Code For Request Is Not Allowed-Syngenta Seeds Only Allows Order Type Code NE or KN For Grower Order Processing",
        "EC009": "Unacceptable Requested Ship Date-The Requested Ship Date Is Not Correctly Formatted Or Is Outside Of The Date Range Defined As Acceptable For The Current Or Previous Seed Year",
        "EC015": "No Match On Buyer Partner Identifier-Buyer Partner Identifier Is Not Correctly Formatted Or Does Not Match Any Syngenta Seeds Partner Identifier",
        "EC027": "Missing Purchase Order Line Number-Purchase Order Line Number Must Be Present For Order Management",
        "EC028": "Invalid Product Identifier for Ship To-Product Not Available In Ship To Product Catalog Or Ship To Requires A Contract To Purchase Product",
        "EC030": "Invalid Product Identifier-Product Identifier Is Not Correctly Formatted Or Does Not Match Any Syngenta Seeds Product Identifier",
        "EC032": "Invalid Unit Of Measure-Unit Of Measure Is Not Valid For Product",
        "EC039": "Unacceptable Document Date-Document Date Is Not Correctly Formatted Or Is Outside Of The Date Range Defined As Acceptable For The Current Or Previous Seed Year",
        "EC041": "Unacceptable Purchase Order Issue Date-Purchase Order Issue Date Is Not Correctly Formatted Or Is Outside Of The Date Range Defined As Acceptable For The Current Or Previous Seed Year",
        "EC053": "Ship To Partner Identifier Is Invalid-Ship To Partner Identifier Is Not Correctly Formatted",
        "EC065": "Purchase Order Number Not Specified-Purchase Order Number Must Be Present For Order Management",
        "EC098": "Order Accepted Conditionally-Order Request Successfully Processed By Syngenta Seeds But Ship To Stewardship Agreement Is Required",
        "EC100": "Seed Year Not Allowed For Processing-Order Management Can Only Be Performed For The Current Seed Year",
        "EC102": "Action Request Not Valid For Order Management-Action Request Must Be Add, Change, Replace Or Delete For Order Management",
        "EC109": "Invalid Product Quantity For Order Line Addition-Product Quantity Must Be Greater Than Zero For Addition Of New Order Line"
    }
    '''

    // Parse the JSON body
    def jsonSlurper = new JsonSlurper()
    def jsonObject = jsonSlurper.parseText(jsonBody)

      // Store the JSON object in a property as a JSON string
    message.setProperty("ErrorCodes", JsonOutput.toJson(jsonObject))

    // // Optionally, set the JSON as the message body
    // message.setBody(JsonOutput.prettyPrint(JsonOutput.toJson(jsonObject)))

    return message
}

import java.text.SimpleDateFormat
import java.util.Calendar
import java.util.Date
import com.sap.gateway.ip.core.customdev.util.Message

// Message processing
def Message processData(Message message) {
    // Retrieve the year to check from message properties
    def yearToCheck = message.getProperty("seedYear") as Integer

    // Get the current date
    def currentDate = new Date()

    // Define the fiscal start date format
    def formatter = new SimpleDateFormat("MM/dd/yyyy")

    // Get the current year
    def calendar = Calendar.getInstance()
    calendar.setTime(currentDate)
    def currentYear = calendar.get(Calendar.YEAR)

    // Determine the fiscal start date
    def fiscalStartDateValue = "10/01/$currentYear"
    def fiscalStartDate = formatter.parse(fiscalStartDateValue)

    // Calculate the fiscal year
    def fiscalYear
    if (currentDate.after(fiscalStartDate)) {
        fiscalYear = currentYear + 1
    } else {
        fiscalYear = currentYear
    }

    // Check if the year to check is valid
    def isValid = (yearToCheck == fiscalYear || yearToCheck == fiscalYear - 1 || yearToCheck == fiscalYear + 1)

    // Set the result as a message property
    message.setProperty("isValidMarketYear", isValid)

    return message
}

import java.text.SimpleDateFormat
import java.util.Calendar
import java.util.Date
import com.sap.gateway.ip.core.customdev.util.Message
import groovy.json.JsonOutput
import groovy.json.JsonSlurper

def Message processData(Message message) {
    def body = message.getBody(String)
    def payload = new JsonSlurper().parseText(body)
    def output = []

    // Helper functions
    def getCurrentYear = {
        def currentMonth = new Date().format("MM")
        def currentYear = new Date().format("yyyy").toInteger()
        if (["10", "11", "12"].contains(currentMonth)) {
            return (currentYear + 1).toString()
        }
        return currentYear.toString()
    }

    def checkYear = { DateYear, DateMonth ->
        def currentYear = getCurrentYear().toInteger()
        if (["10", "11", "12"].contains(DateMonth) && 
            ((DateYear.toInteger() + 1 == currentYear) || 
             (DateYear.toInteger() + 1 == currentYear - 1) || 
             (DateYear.toInteger() + 1 == currentYear + 1))) {
            return "Success"
        }
        if (["01", "02", "03", "04", "05", "06", "07", "08", "09"].contains(DateMonth) && 
            ((DateYear.toInteger() == currentYear) || 
             (DateYear.toInteger() == currentYear - 1) || 
             (DateYear.toInteger() == currentYear + 1))) {
            return "Success"
        }
        return "Failed"
    }

    def isValidMarketYear = { yearToCheck ->
        def currentDate = new Date()
        def formatter = new SimpleDateFormat("MM/dd/yyyy")
        def calendar = Calendar.getInstance()
        calendar.setTime(currentDate)
        def currentYear = calendar.get(Calendar.YEAR)
        def fiscalStartDateValue = "10/01/$currentYear"
        def fiscalStartDate = formatter.parse(fiscalStartDateValue)
        def fiscalYear = currentDate.after(fiscalStartDate) ? currentYear + 1 : currentYear
        return (yearToCheck == fiscalYear || yearToCheck == fiscalYear - 1 || yearToCheck == fiscalYear + 1)
    }

    // Process ProductBooking
    def productBookingBodies = payload.ProductBooking?.ProductBookingBody
    if (!(productBookingBodies instanceof List)) {
        productBookingBodies = [productBookingBodies]
    }

    productBookingBodies.each { productBookingBody ->
        def productBookingProperties = productBookingBody?.ProductBookingProperties
        def productBookingPartners = productBookingBody?.ProductBookingPartners
        def productBookingDetails = productBookingBody?.ProductBookingDetails

        def result = [
            reqCustOrdNum: productBookingProperties?.ProductBookingOrderNumber ?: "EC002",
            GrowerGLN: productBookingPartners?.ShipTo?.PartnerInformation?.PartnerIdentifier,
            EC005: (["New", "Changed", "Cancelled", "Summary Request"].contains(productBookingProperties?.ProductBookingType)) ? productBookingProperties?.ProductBookingType : "EC005",
            EC006: (["NE", "KN"].contains(productBookingProperties?.ProductBookingOrderTypeCode)) ? "Success" : "EC006",
            EC041: (checkYear((productBookingProperties?.ProductBookingOrderIssuedDate?.DateTime?.split("-")[0]), 
                              (productBookingProperties?.ProductBookingOrderIssuedDate?.DateTime?.split("-")[1])) == "Success") ? "Success" : "EC041",
            EC053: (productBookingPartners?.ShipTo?.PartnerInformation?.PartnerIdentifier?.size() == 13) ? "Success" : "EC053",
            EC100: (isValidMarketYear(productBookingProperties?.ProductYear?.toInteger())) ? "Success" : "EC100",
            EC065: (!["", "9999999999", "0000000000"].contains(productBookingProperties?.ProductBookingOrderNumber)) ? "Success" : "EC065",
            productItem: productBookingDetails?.ProductBookingProductLineItem ? [productBookingDetails?.ProductBookingProductLineItem].flatten().collect { item ->
                [
                    GTIN: item?.ProductIdentification?.ProductIdentifier,
                    reqCustOrdLineNum: item?.ProductBookingOrderLineItemNumber ?: "EC027",
                    EC009: (checkYear((item?.RequestedShipDateTime?.DateTimeInformation?.DateTime?.split("-")[0]), 
                                      (item?.RequestedShipDateTime?.DateTimeInformation?.DateTime?.split("-")[1])) == "Success") ? "Success" : "EC009",
                    EC027: (!["", "000000", "999999"].contains(item?.ProductBookingOrderLineItemNumber)) ? "Success" : "EC027",
                    EC032: (item?.ProductQuantity?.Measurement?.UnitOfMeasureCode == "BG") ? "Success" : "EC032",
                    EC102: (["Add", "Change", "Delete"].contains(item?.ActionRequest)) ? "Success" : "EC102",
                    EC109: (item?.ActionRequest?.toLowerCase() == "add" && item?.ProductQuantity?.Measurement?.MeasurementValue.toDouble() <= 0) ? "EC109" : "Success"
                ]
            } : []
        ]
        output << result
    }

    // Set the message body
    def outputJson = JsonOutput.prettyPrint(JsonOutput.toJson(output))
    // message.setBody(outputJson)

    // Set the output as a property
    message.setProperty("checkError", outputJson)
    return message
}

import com.sap.gateway.ip.core.customdev.util.Message
import groovy.json.JsonOutput
import groovy.json.JsonSlurper

def processData(Message message) {
    def jsonSlurper = new JsonSlurper()

    // Parse the properties
    def checkError = message.getProperty("checkError")
    if (checkError instanceof String) {
        checkError = jsonSlurper.parseText(checkError)
    }

    def errorCodes = message.getProperty("ErrorCodes")
    if (errorCodes instanceof String) {
        errorCodes = jsonSlurper.parseText(errorCodes)
    }

    // Helper function to extract error details
    def getErrorDetails = { errorCode, errorKey ->
         if (errorCode?.startsWith("EC")) {
            def errorDescription = errorCodes[errorKey]
            [
                id: errorKey.replace("EC", ""),
                description: errorDescription.split("-")[0],
                comments: errorDescription.split("-")[1]
            ]
        } else {
            null
        }
    }

    // Process the checkError data
    def output = checkError.collect { d1 ->
        def headerErrors = [
			getErrorDetails(d1.EC005, "EC005"),
            getErrorDetails(d1.EC006, "EC006"),
            getErrorDetails(d1.EC041, "EC041"),
            getErrorDetails(d1.EC053, "EC053"),
            getErrorDetails(d1.EC100, "EC100"),
            getErrorDetails(d1.EC065, "EC065")
        ].findAll { it != null }

        def productItems = d1.productItem.collect { d2 ->
            def lineErrors = [
                getErrorDetails(d2.EC027, "EC027"),
				getErrorDetails(d2.EC009, "EC009"),
                getErrorDetails(d2.EC032, "EC032"),
                getErrorDetails(d2.EC102, "EC102"),
                getErrorDetails(d2.EC109, "EC109")
            ].findAll { it != null }

            [
                GTIN: d2.GTIN,
                reqCustOrdLineNum: d2.reqCustOrdLineNum,
                LineError: lineErrors
            ]
        }

        [
            reqCustOrdNum: d1.reqCustOrdNum,
            GrowerGLN: d1.GrowerGLN,
            HeaderError: headerErrors,
            productItem: productItems
        ]
    }

    // Set the output as the message body
    def outputJson = JsonOutput.prettyPrint(JsonOutput.toJson(output))
    // message.setBody(outputJson)

    // Set the output as a property
    message.setProperty("setErrorList", outputJson)

    return message
}

import com.sap.gateway.ip.core.customdev.util.Message
import groovy.json.JsonSlurper
import groovy.json.JsonOutput

def Message processData(Message message) {
    def properties = message.getProperties()

    def setErrorList = new JsonSlurper().parseText(properties.get("setErrorList"))
    def resellerGLN = properties.get("resellerGLN")?.replaceAll("'", "") // Remove single quotes
    def seedYear = properties.get("seedYear")

    def getGrowerStatus = { custnum, Grower ->
        setErrorList.orderDetail.find { it.GrowerGLN == Grower && it.reqCustOrdNum == custnum }
    }

    def geterrorGrower = { custnum, Grower ->
        setErrorList.orderDetail.find { it.GrowerGLN == Grower && it.reqCustOrdNum == custnum }?.HeaderError
    }

    def geterrorProduct = { custnum, Grower, GTIN ->
        setErrorList.orderDetail.find { it.GrowerGLN == Grower && it.reqCustOrdNum == custnum }?.productItem?.find { it.GTIN == GTIN }?.LineError
    }

    def body = message.getBody(String)

    // Check if the body is empty or null
    if (!body) {
        message.setBody("{}")
        return message
    }

    def payload = new JsonSlurper().parseText(body)

    def result = [
        newGrowers: [
            resellerGLN: setErrorList.resellerGLN,
            growers: setErrorList.growers
        ],
        orderDetail: []
    ]

    def productBookings = payload.ProductBooking
    def productBookingBodies = productBookings.ProductBookingBody
    if (!(productBookingBodies instanceof List)) {
        productBookingBodies = [productBookingBodies]
    }

    productBookingBodies.each { value ->
        def reqCustOrdNum = value.ProductBookingProperties.ProductBookingOrderNumber
        def GrowerGLN = value.ProductBookingPartners.ShipTo.PartnerInformation.PartnerIdentifier
        def orderDetail = [
            reqDocIdentifier: productBookings.Header.ThisDocumentIdentifier.DocumentIdentifier ?: null,
            reqSellerGLN: resellerGLN,
            reqBuyerGLN: GrowerGLN,
            reqBuyerSFDCId: getGrowerStatus(reqCustOrdNum, GrowerGLN)?.growerSFDCId ?: getGrowerStatus(reqCustOrdNum, GrowerGLN)?.GrowerGLN,
            reqPayerGLN: value.ProductBookingPartners.Payer.PartnerInformation.PartnerIdentifier,
            reqSeedYear: seedYear,
            reqCustOrdNum: reqCustOrdNum,
            reqProdBookType: value.ProductBookingProperties.ProductBookingType,
            reqSynOrdNum: (value.ProductBookingProperties.ReferenceInformation.DocumentReference.DocumentIdentifier.startsWith("SO-") || value.ProductBookingProperties.ReferenceInformation.DocumentReference.DocumentIdentifier == "9999999999") ? value.ProductBookingProperties.ReferenceInformation.DocumentReference.DocumentIdentifier : "SO-20" + value.ProductBookingProperties.ReferenceInformation.DocumentReference.DocumentIdentifier,
            respExceptions: geterrorGrower(reqCustOrdNum, GrowerGLN) ?: [],
            productItem: []
        ]

        def productBookingDetails = value.ProductBookingDetails
        def productLineItems = productBookingDetails.ProductBookingProductLineItem
        if (!(productLineItems instanceof List)) {
            productLineItems = [productLineItems]
        }

        productLineItems.each { value1 ->
            def GTIN = value1.ProductIdentification.ProductIdentifier
            def productItem = [
                reqProdGTIN: GTIN,
                reqProdQty: value1.ProductQuantity.Measurement.MeasurementValue,
                reqType: value1.ActionRequest,
                reqRDD: value1.RequestedShipDateTime.DateTimeInformation.DateTime,
                reqCustOrdLineNum: value1.ProductBookingOrderLineItemNumber,
                reqSynOrdLineNum: value1.LineNumber,
                reqM2MOrderRef: reqCustOrdNum + "|" + value1.ProductBookingOrderLineItemNumber,
                reqProdQtyDelta: value1.IncreaseOrDecrease.ProductQuantityChange.Measurement.MeasurementValue,
                respExceptions: geterrorProduct(reqCustOrdNum, GrowerGLN, GTIN) ?: []
            ]
            orderDetail.productItem << productItem
        }

        result.orderDetail << orderDetail
    }

    message.setProperty("sfRequest", JsonOutput.prettyPrint(JsonOutput.toJson(result)))
    message.setBody(JsonOutput.prettyPrint(JsonOutput.toJson(result)))
    return message
}

import com.sap.gateway.ip.core.customdev.util.Message
import groovy.json.JsonSlurper
import groovy.json.JsonOutput

def Message processData(Message message) {
    def properties = message.getProperties()

    // Parse the sfrequest property
    def sfrequest = new JsonSlurper().parseText(properties.get("sfRequest"))

    // Initialize the result
    def result = [
        newGrowers: sfrequest.newGrowers,
        orderDetail: sfrequest.orderDetail.collect { order ->
            def combinedRespExceptions = (order.respExceptions + order.productItem.collect { it.respExceptions }.flatten()).unique()
            order.remove('respExceptions')
            order + [respExceptions: combinedRespExceptions]
        }
    ]

    // Set the formatted JSON as a property
    message.setProperty("sfRequest",JsonOutput.prettyPrint(JsonOutput.toJson(result)))
    message.setBody(JsonOutput.prettyPrint(JsonOutput.toJson(result)))
    return message
}

import com.sap.gateway.ip.core.customdev.util.Message
import groovy.json.JsonSlurper
import groovy.json.JsonOutput

def Message processData(Message message) {
    // Retrieve the sfresponse property
    def sfresponse = message.getProperty("sfresponse")

    // Parse the JSON string into a Groovy object
    def jsonSlurper = new JsonSlurper()
    def response = jsonSlurper.parseText(sfresponse)

    // Process the data
    def result = response.collectMany { value ->
        value.productItem.collect { item ->
            def reqSynOrdNum = value.reqSynOrdNum
            if (reqSynOrdNum?.startsWith("SO-")) {
                if (reqSynOrdNum.size() > 18) {
                    reqSynOrdNum = reqSynOrdNum.substring(reqSynOrdNum.indexOf("-20") + 3)
                } else {
                    reqSynOrdNum = reqSynOrdNum.substring(reqSynOrdNum.indexOf("-20") + 3)
                }
            }

            [
                reqCustOrdNum: value.reqCustOrdNum ?: "",
                reqCustOrdLineNum: item.reqCustOrdLineNum ?: "",
                reqSynOrdNum: reqSynOrdNum ?: value.reqSynOrdNum,
                reqSynOrdLineNum: item.reqSynOrdLineNum ?: "",
                reqProdGTIN: item.reqProdGTIN ?: "",
                reqProdQty: item.reqProdQty != null ? String.format("%.3f", item.reqProdQty.toDouble()) : null,
                reqRDD: item.reqRDD ?: "",
                reqType: item.reqType ?: "",
                respAvailProdQty: item.respAvailProdQty != null ? String.format("%.3f", item.respAvailProdQty.toDouble()) : null,
                respExceptions: value.respExceptions instanceof List ? value.respExceptions : [],
                respExceptionsLine: item.respExceptions ?: "",
                reqProdQtyDelta: item.reqProdQtyDelta != null ? String.format("%.3f", item.reqProdQtyDelta.toDouble()) : null,
                respAvailStatus: item.respAvailStatus ?: "",
                respLongShortQty: item.respLongShortQty != null ? String.format("%.3f", Math.abs(item.respLongShortQty.toDouble())) : null,
                reqM2MOrderRef: item.reqM2MOrderRef ?: "",
                respSpcInstr: value.respSpcInstr ?: "",
                respProdName: item.respProdName ?: "",
                respPOQty: (item.respPOQty == null && item.respBOQty == null) ? null : 
                           String.format("%.3f", ((item.respPOQty?.abs()?.toDouble() ?: 0.0) + (item.respBOQty?.abs()?.toDouble() ?: 0.0))),
                respTotalPOQty: (item.respTotalPOQty == null && item.respTotalBOQty == null) ? null : 
                                String.format("%.3f", ((item.respTotalPOQty?.toDouble() ?: 0.0) + (item.respTotalBOQty?.toDouble() ?: 0.0))),
                respTotalGrowerQty: item.respTotalGrowerQty != null ? String.format("%.3f", item.respTotalGrowerQty.toDouble()) : null
            ]
        }
    }

    // Wrap the result in a root element for proper XML conversion
    def wrappedResult = [response: result]

    // Convert the result back to JSON with pretty print
    def jsonOutput = JsonOutput.prettyPrint(JsonOutput.toJson(wrappedResult))
    message.setBody(jsonOutput)

    return message
}

